scwin.memJson = $c.data.getMemInfo();
scwin.privAdmin = $c.gus.cfIsNull(scwin.memJson.privAdmin) ? '' : scwin.memJson.privAdmin;
scwin.today = $c.date.getServerDateTime("yyyyMMdd");

scwin.g_sCurrDate = scwin.today;

scwin.g_sLoginDept = $c.gus.cfIsNull(scwin.memJson.acctDeptCd) ? '' : scwin.memJson.acctDeptCd;
scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;
scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd;
scwin.vUserHomeClsCd = $c.gus.cfIsNull(scwin.memJson.userHomeClsCd) ? '' : scwin.memJson.userHomeClsCd;

scwin.isSubCompany = false;

scwin.coCd = "000";
scwin.coClsCd = "0";

//hidden
scwin.txt_stYm = "";
scwin.txt_endYm = "";
scwin.txt_submitDt = "";
scwin.txtCoClsCd = "";
scwin.declarYr = "";
scwin.vatQuartYyClsCd = "";
scwin.txt_evidClsNm = "";

scwin.txt_stYm2 = "";
scwin.txt_endYm2 = "";
scwin.txt_submitDt2 = "";
scwin.txtCoClsCd2 = "";
scwin.declarYr2 = "";
scwin.vatQuartYyClsCd2 = "";
scwin.txt_evidClsNm2 = "";

scwin.onpageload = function () {
    const codeOptions = [
        { grpCd: "FI019", compID: "lc_pchsSellClsCd, lc_pchsSellClsCd2" }
    ];
    // console.log(" codeOptions : "+ JSON.stringify(codeOptions));
    $c.data.setCommonCode(codeOptions);

};

scwin.onUdcCompleted = function () {
    scwin.f_defaultValue();
    scwin.f_setCompanyInfo();
}

scwin.ondataload = function () {
    $c.data.setPopupTitle('e세로증빙등록(팝업)');
}

//-------------------------------------------------------------------------
// default값 생성
//-------------------------------------------------------------------------	
scwin.f_defaultValue = function () {
    let valueObject = $c.data.getParameter();

    console.log("valueObject =>");
    console.log(valueObject);
    console.log(valueObject.startDt);

    // debis list 받아오는거
    ed_startDt.setValue(valueObject.startDt);
    ed_endDt.setValue(valueObject.endDt);
    ed_coCd.setValue(valueObject.coCd);			// 코드
    ed_coNm.setValue(valueObject.coNm);			// 회사명 

    var tmpAcctDeptCd = '';
    if (/^\d+$/.test(valueObject.acctDeptCd)) {
        tmpAcctDeptCd = valueObject.acctDeptCd;
    }
    ed_AcctDeptCd.setValue(tmpAcctDeptCd);
    ed_tsBusiNo.setValue(valueObject.tsBusiNo);		//신고자사업자
    ed_AcctDeptNm.setValue(valueObject.tsBusiNm);
    ed_supBusiNo.setValue(valueObject.supBusiNo);	//공급자사업자
    ed_supBusiNm.setValue(valueObject.supBusiNm);
    ed_regId.setValue(valueObject.regId);		//등록자
    ed_empNm.setValue(valueObject.regNm);
    ed_slipNo.setValue(valueObject.slipNo);		//전표번호

    // esero list 받아오는거
    ed_startDt2.setValue(valueObject.startDt);
    ed_endDt2.setValue(valueObject.endDt);
    var tmpAcctDeptCd2 = '';
    if (/^\d+$/.test(valueObject.acctDeptCd)) {
        tmpAcctDeptCd2 = valueObject.acctDeptCd;
    }
    ed_AcctDeptCd2.setValue(tmpAcctDeptCd2);
    ed_tsBusiNo2.setValue(valueObject.tsBusiNo);		//신고자사업자
    ed_AcctDeptNm2.setValue(valueObject.tsBusiNm);
    ed_supBusiNo2.setValue(valueObject.supBusiNo);	//공급자사업자
    ed_supBusiNm2.setValue(valueObject.supBusiNm);
    //txt_etaxId.value        = valueObject.etaxId;
    ed_eseroSupAmt.setValue(valueObject.eseroSupAmt);
}

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function () {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }

    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.coCd = scwin.vLoginCoCd;
    scwin.coClsCd = scwin.vLoginCoClsCd;

    //scwin.f_PopUpCompanyInfo('T'); 

    udc_coCd.setSelectId("retrieveDongbuGroupCompanyInfo");
    udc_coCd.cfCommonPopUp(
        scwin.udc_init_coCd_cb
        , ed_coCd.getValue(), ed_coNm.getValue()
        , 'T', null, null, null, null
        , null, null, null, null, null);
}

scwin.udc_init_coCd_cb = function (rtnList) {
    console.log(rtnList);
    // SET	 
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;

        ed_coCd.setValue(rtnList[0]);	// 코드
        ed_coNm.setValue(rtnList[5]); // 회사명 
        scwin.txtCoClsCd = rtnList[1];	// 회사구분  
        scwin.coCd = ed_coCd.getValue();
        scwin.coClsCd = rtnList[1];	// 회사구분  
    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        scwin.txtCoClsCd = "";
        scwin.coCd = "";
        scwin.coClsCd = "";
    }


    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  	// 자회사 회계 시스템 
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }

    if ('T' == scwin.privAdmin || !scwin.isSubCompany) {  // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
        $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
    } else {
        $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
    }


    // 회사코드 변경권한
    if (scwin.g_sLoginDept != '00009') {
        $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
    } else {
        $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
    }

    //공급자사업자번호 변경 불가
    $c.gus.cfDisableObjects([ed_supBusiNo, ed_supBusiNm, ed_supBusiNo2, ed_supBusiNm2, btn_mgntClntNo, btn_mgntClntNo2]);

    lc_evidClsCd.setSelectedIndex(0);
    scwin.f_Retrieve1();
    scwin.f_Retrieve2();
}





scwin.btn_search_onclick = function (e) {
    scwin.f_Retrieve1();
};

scwin.btn_search2_onclick = function (e) {
    scwin.f_Retrieve2();
};

scwin.btn_close_onclick = function (e) {
    $c.win.closePopup();
};

scwin.btn_oz_onclick = function (e) {
    scwin.f_OzReport2();
};

scwin.btn_del_onclick = function (e) {
    scwin.f_Delete();
};

scwin.btn_save_onclick = function (e) {
    scwin.f_Save();
};

scwin.udc_coCd_onclickEvent = function (e) {
    scwin.f_PopUpCompanyInfo('F');
};

scwin.udc_AcctDeptCd_onclickEvent = function (e) {
    scwin.f_SearchPopUp('4', 'F');
};

scwin.udc_supBusiNo_onclickEvent = function (e) {
    scwin.f_SearchPopUp('3', 'F');
};

scwin.udc_regId_onclickEvent = function (e) {
    scwin.f_SearchPopUp('2', 'F');
};

scwin.udc_AcctDeptCd2_onclickEvent = function (e) {
    scwin.f_SearchPopUp2('4', 'F');
};

scwin.udc_supBusiNo2_onclickEvent = function (e) {
    scwin.f_SearchPopUp2('3', 'F');
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve1 = function () {

    // 시작, 종료일자 체크
    if (ed_startDt.getValue() == "" || ed_endDt.getValue() == "") {
        $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["기간"]);
        ed_startDt.focus();
        return;
    }

    //시작일자가 종료일자 이전인지 check
    if (!$c.gus.cfIsAfterDate(ed_startDt.getValue(), ed_endDt.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return;
    }

    dma_search.set("startDt", ed_startDt.getValue());
    dma_search.set("endDt", ed_endDt.getValue());
    dma_search.set("tsBusiNo", ed_tsBusiNo.getValue());
    dma_search.set("supBusiNo", ed_supBusiNo.getValue());
    dma_search.set("evidClsCd", lc_evidClsCd.getValue());
    dma_search.set("pchsSellClsCd", lc_pchsSellClsCd.getValue());
    dma_search.set("regId", ed_regId.getValue());
    dma_search.set("slipNo", ed_slipNo.getValue());
    dma_search.set("coCd", ed_coCd.getValue());

    $c.sbm.execute(sbm_search);
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve2 = function () {

    // 시작, 종료일자 체크
    if (ed_startDt2.getValue() == "" || ed_endDt2.getValue() == "") {
        $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["기간"]);
        ed_startDt.focus();
        return;
    }

    //시작일자가 종료일자 이전인지 check
    if (!$c.gus.cfIsAfterDate(ed_startDt2.getValue(), ed_endDt2.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return;
    }

    dma_search2.set("startDt", ed_startDt2.getValue());
    dma_search2.set("endDt", ed_endDt2.getValue());
    dma_search2.set("tsBusiNo", ed_tsBusiNo2.getValue());
    dma_search2.set("supBusiNo", ed_supBusiNo2.getValue());
    dma_search2.set("supBusiNm", ed_supBusiNm2.getValue());
    dma_search2.set("pchsSellClsCd", lc_pchsSellClsCd2.getValue());

    dma_search2.set("etaxId", ed_etaxId.getValue());
    dma_search2.set("eseroSupAmt", ed_eseroSupAmt.getValue());
    dma_search2.set("coCd", ed_coCd.getValue());

    $c.sbm.execute(sbm_search2);
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    if (ds_evid.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_056, Array("(DEBIS 전표 List) 데이타"));
        return;
    }

    if (ds_evid2.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_056, Array("(E세로 List) 데이타"));
        return;
    }

    let chkCnt = 0;
    let chkCnt2 = 0;
    for (i = 0; i < ds_evid.getRowCount(); i++) {
        if (ds_evid.getCellData(i, "chk") == "T") {
            chkCnt++;
            break;
        }
    }

    for (i = 0; i < ds_evid2.getRowCount(); i++) {
        if (ds_evid2.getCellData(i, "chk") == "T") {
            chkCnt2++;
            break;
        }
    }

    if (chkCnt == 0) {
        $c.win.alert("DEBIS 전표 List 중 선택한 항목이 없습니다.");
        return false;
    }

    if (chkCnt2 == 0) {
        $c.win.alert("E세로 List 중 선택한 항목이 없습니다.");
        return false;
    }

    if (ds_evid.getCellData(ds_evid.getRowPosition(), "regYn") == "Y") {
        $c.win.alert("DEBIS 전표 List 중" + ds_evid.getRowPosition() + "번째 항목은 이미 등록 완료 되었습니다.");
        return false;
    }

    if (ds_evid2.getCellData(ds_evid2.getRowPosition(), "regYn") == "Y") {
        $c.win.alert("E세로 List 중" + ds_evid2.getRowPosition() + "번째 항목은 이미 등록 완료 되었습니다.");
        return false;
    }


    let supAmtSum1 = 0;
    let supAmtSum2 = 0;

    let vatSum1 = 0;
    let vatSum2 = 0;

    for (i = 0; i < ds_evid.getRowCount(); i++) {
        if (ds_evid.getCellData(i, "chk") == "T") {
            supAmtSum1 = supAmtSum1 + ds_evid.getCellData(i, "debisSupAmt");
            vatSum1 = vatSum1 + ds_evid.getCellData(i, "debisVatAmt");
        }
    }

    for (i = 0; i < ds_evid2.getRowCount(); i++) {
        if (ds_evid2.getCellData(i, "chk") == "T") {
            supAmtSum2 = supAmtSum2 + ds_evid2.getCellData(i, "eseroSupAmt");
            vatSum2 = vatSum2 + ds_evid2.getCellData(i, "eseroVatAmt");
        }
    }

    if (vatSum1 != vatSum2) {
        $c.win.alert("선택한 DEBIS 부가세금액의 합과 선택한 E세로 부가세금액의 합이 같지 않습니다.");
        return false;
    }

    if (supAmtSum1 != supAmtSum2) {
        $c.win.alert("선택한 DEBIS 공급금액의 합과 선택한 E세로 공급금액의 합이 같지 않습니다.");
        return false;
    }

    let ret;
    ret = await $c.win.confirm(MSG_CM_CRM_001);
    if (ret == true) {
        //tr_save.Action = "/ac.fi.taxbiz.evidmgnt.RegistEseroEvidenceMgntPopupCMD.do";
        //tr_save.Post();
        $c.sbm.execute(sbm_save);
    }
}

//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------
scwin.f_resultPopEd = function (strCd, strNm, rtnList) {

    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            return;
        }
        strCd.setValue(rtnList[0]);	// 코드
        strNm.setValue(rtnList[1]);	// 명
        strCd.options.hidVal = rtnList[0];  // 히든값
    } else {
        strCd.setValue("");
        strNm.setValue("");
        strCd.options.hidVal = "";
    }

}

//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------	
scwin.f_checkPopEd = function (strCd, strNm, flag) {
    strNm.setValue("");
    strCd.options.hidVal = "";
    if (strCd.getValue().trim() != "") scwin.f_SearchPopUp(flag, 'T');
}
//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------	
scwin.f_checkPopEd2 = function (strCd, strNm, flag) {
    strNm.setValue("");
    strCd.options.hidVal = "";
    if (strCd.getValue().trim() != "") scwin.f_SearchPopUp2(flag, 'T');
}

scwin.udc_regId_cb = function (rtnList) {
    scwin.f_resultPopEd(ed_regId, ed_empNm, rtnList);
}

scwin.udc_supBusiNo_cb = function (rtnList) {
    scwin.f_resultPopEd(ed_supBusiNo, ed_supBusiNm, rtnList);
}

scwin.udc_AcctDeptCd_cb = function (rtnList) {
    debugger;
    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            return;
        }
        ed_AcctDeptCd.setValue(rtnList[2]);		//부가세부서코드
        ed_AcctDeptNm.setValue(rtnList[3]);		//부가세부서명
        ed_tsBusiNo.setValue(rtnList[5]);		//부가세사업자번호
        ed_AcctDeptCd.options.hidVal = rtnList[2];  	//히든값        
    } else {
        ed_AcctDeptCd.setValue("");
        ed_AcctDeptNm.setValue("");
        ed_tsBusiNo.setValue("");
    }
}

//-------------------------------------------------------------------------
// function name : f_SearchPopUp
// function desc : 조회 팝업
// function Parameter : null 
//-------------------------------------------------------------------------
scwin.f_SearchPopUp = function (flag, check) {
    let param;

    switch (flag) {
        case '2':
            // 사번
            param = "" + scwin.coCd;

            udc_regId.setSelectId("retrieveAcEmpInfo");
            udc_regId.cfCommonPopUp(scwin.udc_regId_cb, 
            ed_regId.getValue().trim(), 
            ed_empNm.getValue(), 
            check, 
            null, 
            null, 
            null, 
            null, 
            param, 
            null, 
            null, 
            null, 
            null,
            null,
            'F');

            break;

        case '3':
            // 사업자번호 
            param = "";

            udc_supBusiNo.setSelectId("retrieveCrnInfo");
            udc_supBusiNo.cfCommonPopUp(scwin.udc_supBusiNo_cb, ed_supBusiNo.getValue().trim(), ed_supBusiNm.getValue(), check, null, null, null, null, param, null, null, null, null);

            break;

        case '4':

            // 부가세신고부서조회
            let rtnList;
            param = ",,," + scwin.coCd + "," + scwin.coClsCd + "," + scwin.g_sCurrDate.substring(0, 4);
            udc_AcctDeptCd.setSelectId("retrieveVatDeclarAcctDeptCd");
            debugger;
            udc_AcctDeptCd.cfCommonPopUp(scwin.udc_AcctDeptCd_cb, ed_AcctDeptCd.getValue().trim(), ed_AcctDeptNm.getValue(), check, null, null, null, null, param, null, null, null, null);

            scwin.f_resultPopEd(ed_AcctDeptCd, ed_AcctDeptNm, rtnList);
            break;

        default:
            break;
    }
}

scwin.udc_supBusiNo2_cb = function (rtnList) {
