scwin.f_userToExcel = function () {
    let sheetTitle = "e세로증빙등록";
    const gridId = gr_evid;
    const infoArr = [];
    const options = {
        fileName: sheetTitle + ".xlsx",    // + ".xls",
        sheetName: sheetTitle
    };

    if (ds_evid.getRowCount() <= 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_009, Array("데이타"));  // 출력할 @이(가) 없습니다.
