//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function () {
    if (ds_evid2.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_056, Array("데이타"));
        return;
    }

    let chkCnt = 0;
    for (i = 0; i < ds_evid2.getRowCount(); i++) {
        if (ds_evid2.getCellData(i, "chk") == "T") {
            chkCnt++;
            break;
        }
    }

    if (chkCnt == 0) {
        $c.win.alert("선택한 항목이 없습니다.");
        return false;
    }

    if (ds_evid2.getCellData(ds_evid2.getRowPosition(), "regYn") == "N") {
        $c.win.alert("등록되지 않은 항목 입니다.");
        return false;
    }

    let ret = await $c.win.confirm(MSG_CM_CRM_001);
    if (ret == true) {
        //tr_delete.Action = "/ac.fi.taxbiz.evidmgnt.DeleteEseroEvidenceMgntCMD.do";
        //tr_delete.Post();
        $c.sbm.execute(sbm_delete);
    }
}

